using System.ComponentModel.DataAnnotations;

namespace sv_ec757da5fda04451bcc77de439edfa22.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, MinimumLength = 1, ErrorMessage = "Name must be between 1 and 100 characters.")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Quantity is required.")]
    [Range(0, int.MaxValue, ErrorMessage = "Quantity must be 0 or greater.")]
    public int Quantity { get; set; }

    [Required(ErrorMessage = "Unit Price is required.")]
    [Range(0.01, double.MaxValue, ErrorMessage = "Unit Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public ProductCategory Category { get; set; }
}

public enum ProductCategory
{
    Electronics,
    Clothing,
    Food,
    Other
}

using sv_ec757da5fda04451bcc77de439edfa22.Models;

namespace sv_ec757da5fda04451bcc77de439edfa22.Services;

public class InventoryService
{
    private readonly List<Product> _products;
    private int _nextId;
    private readonly Lock _lock = new();

    public InventoryService()
    {
        _products = new List<Product>
        {
            new() { Id = 1, Name = "Wireless Mouse", Quantity = 50, UnitPrice = 29.99m, Category = ProductCategory.Electronics },
            new() { Id = 2, Name = "USB-C Cable", Quantity = 200, UnitPrice = 9.99m, Category = ProductCategory.Electronics },
            new() { Id = 3, Name = "Cotton T-Shirt", Quantity = 75, UnitPrice = 19.95m, Category = ProductCategory.Clothing },
            new() { Id = 4, Name = "Winter Jacket", Quantity = 30, UnitPrice = 89.50m, Category = ProductCategory.Clothing },
            new() { Id = 5, Name = "Organic Coffee Beans", Quantity = 100, UnitPrice = 14.99m, Category = ProductCategory.Food },
            new() { Id = 6, Name = "Notebook (A5)", Quantity = 150, UnitPrice = 4.50m, Category = ProductCategory.Other },
        };
        _nextId = 7;
    }

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList());
        }
    }

    public Task AddAsync(Product product)
    {
        lock (_lock)
        {
            product.Id = _nextId++;
            _products.Add(new Product
            {
                Id = product.Id,
                Name = product.Name,
                Quantity = product.Quantity,
                UnitPrice = product.UnitPrice,
                Category = product.Category
            });
        }
        return Task.CompletedTask;
    }

    public Task<bool> UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is null) return Task.FromResult(false);

            existing.Name = product.Name;
            existing.Quantity = product.Quantity;
            existing.UnitPrice = product.UnitPrice;
            existing.Category = product.Category;
            return Task.FromResult(true);
        }
    }
}

@using sv_ec757da5fda04451bcc77de439edfa22.Models
@using sv_ec757da5fda04451bcc77de439edfa22.Services
@inject InventoryService InventoryService
@inject NavigationManager Navigation

@* This component is rendered with @rendermode InteractiveServer,
   so it has full interactivity (SignalR) for the edit row only. *@

<tr>
    <EditForm Model="EditModel" OnValidSubmit="Save">
        <DataAnnotationsValidator />
        <td>@Product.Id</td>
        <td>
            <InputText class="form-control form-control-sm" @bind-Value="EditModel.Name" />
            <ValidationMessage For="() => EditModel.Name" />
        </td>
        <td>
            <InputNumber class="form-control form-control-sm" @bind-Value="EditModel.Quantity" />
            <ValidationMessage For="() => EditModel.Quantity" />
        </td>
        <td>
            <InputNumber class="form-control form-control-sm" @bind-Value="EditModel.UnitPrice" />
            <ValidationMessage For="() => EditModel.UnitPrice" />
        </td>
        <td>
            <InputSelect class="form-select form-select-sm" @bind-Value="EditModel.Category">
                @foreach (var cat in Enum.GetValues<ProductCategory>())
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
            <ValidationMessage For="() => EditModel.Category" />
        </td>
        <td>
            <button type="submit" class="btn btn-sm btn-success me-1">Save</button>
            <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="Cancel">Cancel</button>
        </td>
    </EditForm>
</tr>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    private Product EditModel { get; set; } = new();

    protected override void OnInitialized()
    {
        // Copy product data into the edit model so changes can be discarded.
        EditModel = new Product
        {
            Id = Product.Id,
            Name = Product.Name,
            Quantity = Product.Quantity,
            UnitPrice = Product.UnitPrice,
            Category = Product.Category
        };
    }

    private async Task Save()
    {
        await InventoryService.UpdateAsync(EditModel);
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }

    private void Cancel()
    {
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }
}

